      icon: "Py",
      objective: "用 ax.bar() 画分类对比柱状图，用 ax.scatter() 画两个数值变量的关系散点图。",
      starterCode: "import matplotlib\nmatplotlib.use(\"Agg\")\nimport matplotlib.pyplot as plt\n\ncategories = [\"华东\", \"华南\", \"华北\", \"西南\"]\nrevenue = [320, 280, 210, 150]\n\nad_spend = [12, 18, 9, 25, 30, 6, 21, 15]\nclicks = [240, 360, 180, 500, 610, 130, 420, 300]\n\n\ndef draw_bar():\n    fig, ax = plt.subplots()\n    # TODO: 用 ax 的柱状图方法画各区域营收（x 是 categories，高度是 revenue）\n    ax.set_title(\"各区域营收\")\n    ax.set_ylabel(\"营收（万元）\")\n    fig.savefig(\"bar.png\", bbox_inches=\"tight\")\n    return fig, ax\n\n\ndef draw_scatter():\n    fig, ax = plt.subplots()\n    # TODO: 用 ax 的散点图方法画 广告投入 vs 点击量（x=ad_spend, y=clicks）\n    ax.set_title(\"广告投入与点击量\")\n    ax.set_xlabel(\"广告投入（千元）\")\n    ax.set_ylabel(\"点击量\")\n    fig.savefig(\"scatter.png\", bbox_inches=\"tight\")\n    return fig, ax\n\n\nif __name__ == \"__main__\":\n    draw_bar()\n    draw_scatter()\n",
