      starterCode: "import pandas as pd\nfrom sklearn.pipeline import Pipeline\nfrom sklearn.compose import ColumnTransformer\nfrom sklearn.preprocessing import StandardScaler, OneHotEncoder\n\ndf = pd.DataFrame({\n    \"age\":    [25, 40, 33, 52, 29],\n    \"income\": [8000, 20000, 12000, 30000, 9500],\n    \"city\":   [\"北京\", \"上海\", \"北京\", \"广州\", \"上海\"],\n})\n\nnumeric_cols = [\"age\", \"income\"]\ncategorical_cols = [\"city\"]\n\n# TODO: 建 ColumnTransformer:数值列走 StandardScaler,类别列走 OneHotEncoder\n#       transformers 是一个 (名字, 转换器, 列名列表) 的列表\npreprocessor = None\n\n# TODO: 把 preprocessor 放进 Pipeline,步骤名叫 \"prep\"\npipeline = None\n\n# TODO: 对整个 df 一次 fit_transform,得到 features\nfeatures = None\n\nprint(features)\n",
