      starterCode: "def build_context(chunks):\n    \"\"\"把若干块拼成给大模型的上下文，每块前面加方括号编号。\n    返回形如第一块标 1、第二块标 2 的多行字符串。\n    \"\"\"\n    lines = []\n    # TODO: 遍历 chunks 并从 1 开始编号（提示：enumerate 的 start 参数）\n    # TODO: 每行把编号用方括号括起来，后面跟块内容\n    # TODO: 用换行 join 起来返回\n    return \"\"\n\n\ndef format_answer(answer, cited):\n    \"\"\"answer 是模型答案文本，cited 是被引用的编号列表，如 [1, 3]。\n    返回答案 + 末尾的来源标注行。\n    \"\"\"\n    # TODO: 把 cited 里每个编号用方括号包起来，空格连接\n    # TODO: 拼成 answer 加上一行出处标注（用中文标明这些块是答案的依据）\n    return answer\n\n\nif __name__ == \"__main__\":\n    ctx = build_context([\"切块\", \"向量检索\"])\n    print(ctx)\n    print(format_answer(\"RAG 先检索再生成。\", [1, 2]))\n",
