      starterCode: "def chunk_text(text, size=200, overlap=40):\n    \"\"\"把长文本切成带重叠的块，返回字符串列表。\"\"\"\n    chunks = []\n    # TODO: 用 while 循环，从 start=0 开始\n    # 每次取 text[start:start+size] 加进 chunks\n    # 然后 start += size - overlap（让相邻块有重叠）\n    # 直到 start 超过文本长度\n    return chunks\n\n\nif __name__ == \"__main__\":\n    doc = \"检索增强生成把你的资料切块、向量化、存进库里，问问题时先检索再回答。\" * 5\n    parts = chunk_text(doc, size=30, overlap=10)\n    print(len(parts), \"个块\")\n    print(parts[0])\n",
