      starterCode: "import numpy as np\n\n# 一段每日收盘价\nprices = np.array([100.0, 101.5, 100.2, 102.8, 101.0, 103.5, 104.1, 102.0])\n\ndef daily_log_returns(prices):\n    \"\"\"返回相邻两天的对数收益率数组（长度 = len(prices) - 1）。\"\"\"\n    # TODO: 用 np.log(prices[1:] / prices[:-1]) 计算对数收益率\n    return None\n\ndef annualized_volatility(prices, periods_per_year=252):\n    \"\"\"先算对数收益率的样本标准差（日波动率），再年化。\"\"\"\n    rets = daily_log_returns(prices)\n    # TODO: daily_vol = 收益率的标准差(ddof=1)\n    # TODO: 年化 = daily_vol * np.sqrt(periods_per_year)\n    return None\n\nif __name__ == \"__main__\":\n    print(\"日收益率:\", daily_log_returns(prices))\n    print(\"年化波动率:\", annualized_volatility(prices))\n",
